.title-bar {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 38px;
  flex-shrink: 0;
  background: var(--bg-primary);
  border-bottom: 1px solid var(--border-color);
  -webkit-app-region: drag;
  user-select: none;
  position: relative;

  & svg {
    color: var(--text-muted);
    opacity: 0.7;
    transition: opacity 0.15s;
  }

  &:hover svg {
    opacity: 1;
  }
}

